// core/tree/components/CoreToolbar.tsx

import React from 'react';
import { View, StyleSheet, useWindowDimensions } from 'react-native';
import type { ToolbarProps } from '../types';
import { resolveThemeTokenForNative } from '../../../Factory/helpers/style';

const t = resolveThemeTokenForNative;

/* ------------------------------------------------------------------ */
/* Toolbar Component                                                    */
/* ------------------------------------------------------------------ */

const CoreToolbar: React.FC<ToolbarProps> = ({
  start,
  center,
  end,
  className,
  style,
}) => {
  const { width } = useWindowDimensions();
  const isWide = width >= 768;

  const surfaceColor = t('gray.50');
  const borderColor = t('gray.300');

  const renderSection = (content: React.ReactNode | (() => React.ReactNode)) => {
    if (!content) return null;
    return typeof content === 'function' ? content() : content;
  };

  const startContent = renderSection(start);
  const centerContent = renderSection(center);
  const endContent = renderSection(end);

  if (isWide) {
    return (
      <View
        style={[styles.toolbar, { backgroundColor: surfaceColor, borderColor }, style]}
        accessibilityRole="toolbar"
      >
        <View style={styles.startHorizontal}>
          {startContent}
        </View>
        <View style={styles.centerHorizontal}>
          {centerContent}
        </View>
        <View style={styles.endHorizontal}>
          {endContent}
        </View>
      </View>
    );
  }

  return (
    <View
      style={[styles.toolbarVertical, { backgroundColor: surfaceColor, borderColor }, style]}
      accessibilityRole="toolbar"
    >
      {startContent && (
        <View style={styles.startVertical}>
          {startContent}
        </View>
      )}

      {(centerContent || endContent) && (
        <View style={styles.actionsRow}>
          <View style={styles.centerHorizontal}>
            {centerContent}
          </View>
          <View style={styles.endHorizontal}>
            {endContent}
          </View>
        </View>
      )}
    </View>
  );
};

/* ------------------------------------------------------------------ */
/* Styles (layout only — colors applied inline via theme tokens)       */
/* ------------------------------------------------------------------ */

const styles = StyleSheet.create({
  toolbar: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    borderWidth: 1,
    borderRadius: 6,
    paddingHorizontal: 12,
    paddingVertical: 8,
    gap: 8,
  },
  startHorizontal: {
    flexDirection: 'row',
    alignItems: 'center',
    flex: 1,
    flexShrink: 1,
    minWidth: 0,
    gap: 8,
  },
  centerHorizontal: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    flexShrink: 0,
    gap: 4,
  },
  endHorizontal: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'flex-end',
    flexShrink: 0,
    gap: 4,
  },
  toolbarVertical: {
    flexDirection: 'column',
    borderWidth: 1,
    borderRadius: 6,
    paddingHorizontal: 12,
    paddingVertical: 8,
    gap: 8,
  },
  startVertical: {
    flexDirection: 'row',
    alignItems: 'center',
    width: '100%',
    gap: 8,
  },
  actionsRow: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    gap: 8,
  },
});

export default CoreToolbar;
